"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[2598],{2130(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>c,frontMatter:()=>a,metadata:()=>o,toc:()=>h});var s=n(4848),i=n(8453);const a={},r="Chapter 10: The Last Lifeline \u2014 When the Giants Personally Tear Down Their Own Stress Test Arenas",o={id:"GameVictory/\u7b2c\u5341\u7ae0_\u6700\u5f8c\u4e00\u6839\u6551\u547d\u7a3b\u8349_v2",title:"Chapter 10: The Last Lifeline \u2014 When the Giants Personally Tear Down Their Own Stress Test Arenas",description:"On February 23, 2026, Phil Spencer retired.",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/GameVictory/\u7b2c\u5341\u7ae0_\u6700\u5f8c\u4e00\u6839\u6551\u547d\u7a3b\u8349_v2.md",sourceDirName:"GameVictory",slug:"/GameVictory/\u7b2c\u5341\u7ae0_\u6700\u5f8c\u4e00\u6839\u6551\u547d\u7a3b\u8349_v2",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u5341\u7ae0_\u6700\u5f8c\u4e00\u6839\u6551\u547d\u7a3b\u8349_v2",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:"Chapter 9: A Tale of Two CEOs \u2014 Lisa Su vs. Pat Gelsinger",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u4e5d\u7ae0_CEO\u7684\u751f\u6b7b\u6642\u901f_Lisa_Su_vs_Pat_Gelsinger_v2"},next:{title:"Chapter Eleven: A Love Letter to Gamers \u2014 Sega's Sacrifice and Nintendo's Walled Garden",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u5341\u4e00\u7ae0_\u7d66\u904a\u6232\u73a9\u5bb6\u7684\u60c5\u66f8_v4"}},l={},h=[{value:"I. Two Ways to Demolish",id:"i-two-ways-to-demolish",level:2},{value:"II. Fourteen Days",id:"ii-fourteen-days",level:2},{value:"III. The Mirage of Live-Service Games",id:"iii-the-mirage-of-live-service-games",level:2},{value:"IV. Three Mirrors",id:"iv-three-mirrors",level:2},{value:"V. The Same Root Cause of the Disease",id:"v-the-same-root-cause-of-the-disease",level:2},{value:"VI. Closing Arguments",id:"vi-closing-arguments",level:2},{value:"VII. The Loot is Still Being Divided",id:"vii-the-loot-is-still-being-divided",level:2}];function d(e){const t={em:"em",h1:"h1",h2:"h2",header:"header",hr:"hr",img:"img",p:"p",strong:"strong",...(0,i.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"chapter-10-the-last-lifeline--when-the-giants-personally-tear-down-their-own-stress-test-arenas",children:"Chapter 10: The Last Lifeline \u2014 When the Giants Personally Tear Down Their Own Stress Test Arenas"})}),"\n",(0,s.jsx)(t.p,{children:"On February 23, 2026, Phil Spencer retired."}),"\n",(0,s.jsx)(t.p,{children:"Thirty-eight years at Microsoft. The last spokesperson for the Xbox brand trusted by players handed over the keys to his office. The person replacing him was Asha Sharma\u2014the former vice president of Microsoft's CoreAI product division. An AI executive taking over a gaming division."}),"\n",(0,s.jsx)(t.p,{children:"On the exact same day, Xbox President Sarah Bond also left Microsoft."}),"\n",(0,s.jsxs)(t.p,{children:["Two years prior\u2014in January 2024\u2014Microsoft had just finished spending $69 billion to complete the largest gaming acquisition in human business history, buying Activision Blizzard. Three months later, it laid off 1,900 people. In May, it closed Tango Gameworks\u2014the developer of ",(0,s.jsx)(t.em,{children:"Hi-Fi Rush"}),", a Game of the Year nominated title whose studio was disbanded before they even had time for a victory party. On the same day, it closed Arkane Austin\u2014creators of the ",(0,s.jsx)(t.em,{children:"Prey"})," and ",(0,s.jsx)(t.em,{children:"Dishonored"})," series. In September, another 650 people were laid off. In July 2025, another wave: The Initiative closed, the ",(0,s.jsx)(t.em,{children:"Perfect Dark"})," reboot canceled, ",(0,s.jsx)(t.em,{children:"Everwild"})," canceled, and Turn 10 laid off nearly half its staff."]}),"\n",(0,s.jsx)(t.p,{children:"Seamus Blackley\u2014co-creator of the first Xbox in 2001, the man who appeared in Chapter 3\u2014used a phrase on social media: palliative care."}),"\n",(0,s.jsx)(t.p,{children:"End-of-life care."}),"\n",(0,s.jsx)(t.p,{children:"A console, from its birth in Chapter 3 to palliative care, walked a twenty-five-year journey. An arc from an OS defense weapon to an AI sacrifice drew to a close on the day Spencer retired."}),"\n",(0,s.jsx)(t.p,{children:"But Xbox isn't the only machine being dismantled."}),"\n",(0,s.jsx)(t.p,{children:"On the other side of the Pacific, Sony was doing the exact same thing\u2014just using a different excuse."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"i-two-ways-to-demolish",children:"I. Two Ways to Demolish"}),"\n",(0,s.jsx)(t.p,{children:"Microsoft's way of dismantling Xbox is to tear it down in broad daylight."}),"\n",(0,s.jsx)(t.p,{children:"Chapter 3 explained the DNA of the Xbox: it is a wall, not a city. The function of a wall is to block invaders\u2014Sony's PS2 threatened the living room flank of Windows, so Gates built a console to block it. Twenty-five years later, Satya Nadella judged that the living room was no longer a battlefield worth defending. AI was."}),"\n",(0,s.jsx)(t.p,{children:"So the wall was torn down, and the bricks were moved to build another wall."}),"\n",(0,s.jsxs)(t.p,{children:["The $69 billion Activision games were released on PlayStation. Xbox exclusive games were opened up one by one. The hardware team was laid off. Studios were closed one by one. Every step had clear business logic: ",(0,s.jsx)(t.strong,{children:"the gaming division's resources are being systematically transferred to AI infrastructure."})]}),"\n",(0,s.jsx)(t.p,{children:"In fiscal year 2025, Microsoft's capital expenditures exceeded $100 billion\u2014almost entirely directed toward AI data centers. It invested $13 billion in OpenAI. OpenAI promised to purchase $250 billion in Azure cloud services from Microsoft. The magnitude of these numbers makes all of Xbox's losses over twenty-five years look like pocket money."}),"\n",(0,s.jsx)(t.p,{children:"Nadella's logic is simple: the revenue Xbox generates annually is not in the same order of magnitude as the revenue AI could potentially generate. Between a shrinking gaming hardware market and an AI platform that could reshape human productivity, where should the resources go?"}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"From a CEO's perspective, this decision is unassailable. From the perspective of this book, this decision is tearing down an invisible brick."})}),"\n",(0,s.jsx)(t.p,{children:"But Sony's demolition method warrants a closer look. Because Sony wasn't tearing down a wall\u2014it was tearing down a city."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"ii-fourteen-days",children:"II. Fourteen Days"}),"\n",(0,s.jsxs)(t.p,{children:["On August 23, 2024, Sony released a game called ",(0,s.jsx)(t.em,{children:"Concord"}),"."]}),"\n",(0,s.jsx)(t.p,{children:"A hero shooter. Full price at $40. Developer: Firewalk Studios\u2014a studio Sony had just spent money to acquire in April 2023. Development cycle: over eight years. Reported R&D costs ranged from $200 million to $400 million; the industry generally estimated it at well over $200 million."}),"\n",(0,s.jsx)(t.p,{children:"After launch, the peak concurrent player count on Steam was under 700. Combined sales across PS5 and PC were estimated at roughly 25,000 copies."}),"\n",(0,s.jsxs)(t.p,{children:["Fourteen days later\u2014on September 6, 2024\u2014Sony pulled ",(0,s.jsx)(t.em,{children:"Concord"})," from all digital storefronts and offered full refunds."]}),"\n",(0,s.jsx)(t.p,{children:"On October 29, 2024, Sony announced the permanent closure of Firewalk Studios. All 174 employees were laid off. The game would not be brought back online, nor would it be reworked and relaunched."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Over $200 million in R&D investment. 25,000 copies sold. A fourteen-day lifespan."})}),"\n",(0,s.jsx)(t.p,{children:"This wasn't a commercial failure. This was an autopsy report."}),"\n",(0,s.jsxs)(t.p,{children:["And ",(0,s.jsx)(t.em,{children:"Concord"})," wasn't an accident. It was the inevitable product of a systemic decision."]}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"iii-the-mirage-of-live-service-games",children:"III. The Mirage of Live-Service Games"}),"\n",(0,s.jsxs)(t.p,{children:["To understand why ",(0,s.jsx)(t.em,{children:"Concord"})," existed, one must first understand Jim Ryan."]}),"\n",(0,s.jsx)(t.p,{children:'Ryan took over as CEO of Sony Interactive Entertainment in 2019. In 2022, he announced a radical strategic pivot: Sony would launch more than ten "live-service games" by fiscal year 2025.'}),"\n",(0,s.jsx)(t.p,{children:"The commercial logic of live-service games is as seductive as a drug to Wall Street."}),"\n",(0,s.jsx)(t.p,{children:"The revenue model of traditional single-player games is a one-time transaction: the player pays $70, the developer collects the money, end of story. To make another lump sum, you have to develop a sequel from scratch\u2014another three-to-five-year development cycle, another multi-hundred-million-dollar investment, another gamble."}),"\n",(0,s.jsxs)(t.p,{children:['The revenue model of live-service games is recurring income: the game launches for free or at a low price, and then continuously extracts money via season passes, virtual currency, and character cosmetics\u2014so-called "microtransactions." A successful live-service game can be continuously harvested for five to ten years. A single year\'s revenue from ',(0,s.jsx)(t.em,{children:"Fortnite"})," exceeds the lifetime revenue of many AAA blockbusters combined."]}),"\n",(0,s.jsx)(t.p,{children:"What Ryan saw were the numbers on the balance sheet. What he didn't see was the graveyard behind the balance sheet."}),"\n",(0,s.jsxs)(t.p,{children:["The cruelty of the live-service game market lies in this: ",(0,s.jsx)(t.strong,{children:"It is winner-takes-all."})," A player only has so many hours in a day. He is already playing ",(0,s.jsx)(t.em,{children:"Fortnite"}),", already playing ",(0,s.jsx)(t.em,{children:"Apex Legends"}),", already playing ",(0,s.jsx)(t.em,{children:"Valorant"}),"\u2014all for free. You want him to drop the game in his hands and spend $40 to buy a brand new hero shooter he is completely unfamiliar with? Why would he?"]}),"\n",(0,s.jsx)(t.p,{children:'But Ryan didn\'t care about this problem in 2022. He cared about how Wall Street viewed Sony\'s revenue structure. One-time transactions vs. recurring income\u2014in the language of the capital markets, the former is called "unpredictable," and the latter is called "high-quality revenue." Shift more revenue from one-time to recurring, and the price-to-earnings (P/E) ratio goes up, and the stock price goes up.'}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Here, that pattern appears again. Only this time, the convenience isn't for the players; it's for Wall Street."})}),"\n",(0,s.jsx)(t.p,{children:"Ryan issued the order in 2022. Sony's first-party studios began to be required to make live-service games. Not a suggestion; a directive."}),"\n",(0,s.jsxs)(t.p,{children:["Naughty Dog\u2014creators of ",(0,s.jsx)(t.em,{children:"The Last of Us"}),"\u2014were required to make a ",(0,s.jsx)(t.em,{children:"The Last of Us"})," multiplayer online game. After years of development, it was ultimately canceled."]}),"\n",(0,s.jsxs)(t.p,{children:["Insomniac\u2014developer of ",(0,s.jsx)(t.em,{children:"Spider-Man"}),"\u2014made an online game called ",(0,s.jsx)(t.em,{children:"Spider-Man: The Great Web"}),". Canceled."]}),"\n",(0,s.jsxs)(t.p,{children:["Bend Studio\u2014developer of ",(0,s.jsx)(t.em,{children:"Days Gone"}),"\u2014submitted a sequel pitch. Rejected. The team was reassigned to support the live-service development of other projects."]}),"\n",(0,s.jsxs)(t.p,{children:["Bluepoint Games\u2014a studio Sony acquired in 2021, famous for the ",(0,s.jsx)(t.em,{children:"Demon's Souls"})," remake\u2014was required to make an online ",(0,s.jsx)(t.em,{children:"God of War"}),". The project was ultimately canceled, and in February 2026, Sony announced the closure of Bluepoint."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Japan Studio\u2014Sony's founding studio in Tokyo, the cradle of the PlayStation brand\u2014was closed in April 2021."})," Former PlayStation executive Shuhei Yoshida later revealed he was removed from his position because he refused to execute Ryan's directives."]}),"\n",(0,s.jsx)(t.p,{children:"One by one. Studio by studio."}),"\n",(0,s.jsx)(t.p,{children:"The first-party studio ecosystem Sony spent thirty years building\u2014one of the most powerful single-player game development networks in the world\u2014was systematically dismantled in three years. Not because these studios couldn't make good games. It was because the genre of games they made was not the revenue structure Wall Street wanted to see."}),"\n",(0,s.jsxs)(t.p,{children:["Ryan retired in March 2024. The report card of his live-service strategy was already clear by then: the collapse of ",(0,s.jsx)(t.em,{children:"Concord"}),", the cancellation of multiple projects, the closure or restructuring of several studios. The only bright spot was ",(0,s.jsx)(t.em,{children:"Helldivers 2"}),"\u2014but that was a game already in development before the strategic pivot, not Ryan's credit."]}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Ryan had real power. Ryan had a direction. Ryan's direction had been proven wrong."})}),"\n",(0,s.jsx)(t.p,{children:"But we must pause here and ask an uncomfortable question."}),"\n",(0,s.jsx)(t.p,{children:"Did Ryan really lose?"}),"\n",(0,s.jsx)(t.p,{children:"From the players' perspective, yes. From the PlayStation brand's perspective, yes. But from Wall Street's perspective\u2014Jim Ryan was a textbook-successful CEO."}),"\n",(0,s.jsxs)(t.p,{children:['During his tenure, Ryan did several things the capital markets welcomed extremely warmly. First, he moved the core of power and headquarters of Sony Interactive Entertainment from Tokyo to San Mateo, California\u2014a perfect American tech company corporatization. His compensation structure was highly dependent on performance-linked stock options; as long as the revenue on the financial reports hit new highs, he personally made a fortune. Second, he forcefully pushed the porting of PlayStation exclusives to PC\u2014players saw this as a "betrayal" of the exclusivity promise, but Wall Street saw "one asset, earning money twice." Killing two birds with one stone, profits instantly doubled. Third, he exited with perfect timing in March 2024\u2014perfectly dodging the light-speed collapse of ',(0,s.jsx)(t.em,{children:"Concord"}),' five months later, while using the layoff of 900 people and the closure of the London Studio to "dress up the books" right before he left.']}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Ryan left behind a bloated mess of live-service games. But he took with him wealth he couldn't spend in several lifetimes."})}),"\n",(0,s.jsxs)(t.p,{children:["This is not moral criticism. It is a structural observation. In the governance logic of a publicly traded company, Ryan perfectly fulfilled his fiduciary duty to shareholders\u2014maximizing shareholder value during his tenure. As for the soul of PlayStation, the demise of Japan Studio, the $200 million turning to ashes with ",(0,s.jsx)(t.em,{children:"Concord"}),"\u2014these are not in the formula for calculating shareholder value."]}),"\n",(0,s.jsx)(t.p,{children:"And hidden here is a deeper contrast."}),"\n",(0,s.jsx)(t.p,{children:"In 1999, the man standing on the stage at the PS2 launch event\u2014Ken Kutaragi\u2014and Jim Ryan were completely opposite species. Ken Kutaragi was an engineer. He personally designed the Emotion Engine chip, using floating-point performance data to force Gates into building the Xbox (the story of Chapter 3). He defined the gaming ecosystem with technological romance, using the limits of hardware to ask, \"What else can gaming become?\" He ultimately failed too\u2014the PS3's Cell processor was too radically designed, its development difficulty scaring off the entire third-party market\u2014but his failure was an engineer's failure: betting on technology, losing on technology."}),"\n",(0,s.jsxs)(t.p,{children:["Ryan didn't bet on technology. Ryan bet on financial statements. In his eyes, PlayStation wasn't a hardware platform; it was a revenue pipeline. He didn't care how much artistic soul Japan Studio's ",(0,s.jsx)(t.em,{children:"Gravity Rush"})," or ",(0,s.jsx)(t.em,{children:"ICO"}),' had\u2014he cared about the "monthly active users" and "profit margins" of those games. When the numbers weren\'t met, the studio was closed. When Wall Street said recurring revenue was good, all studios pivoted to live-service games.']}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Ken Kutaragi didn't destroy Sony's financials. Ryan didn't destroy Sony's financials either. What Ryan destroyed was the soul of PlayStation\u2014he turned a hardware kingdom built by an engineer into a vulgar, American-style content distribution platform."})}),"\n",(0,s.jsx)(t.p,{children:'And the coldest fact is: in the language of the capital markets, "destroying the soul" is not a KPI. No analyst will ask you on an earnings call: "Does your platform still have a soul?"'}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"iv-three-mirrors",children:"IV. Three Mirrors"}),"\n",(0,s.jsx)(t.p,{children:"Now let's put the three CEOs together."}),"\n",(0,s.jsx)(t.p,{children:"Pat Gelsinger. Lisa Su. Jim Ryan."}),"\n",(0,s.jsx)(t.p,{children:"The conclusion of Chapter 9 was: The victors of tech history are not the smartest people, they are the ones in the right system, holding enough real power, who dare to bet everything."}),"\n",(0,s.jsx)(t.p,{children:"That conclusion is correct. But incomplete."}),"\n",(0,s.jsx)(t.p,{children:'Because it only answered "why some people win." It didn\'t answer "why some people lose"\u2014and there is more than one way to lose.'}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Gelsinger's failure: No real power."})," Chapter 9 has already analyzed this in detail. Intel's MDF system and one-stop service teams had solidified into interest groups. Gelsinger saw all the problems, but he couldn't move the machine. Wall Street didn't give him time, and the board didn't give him the knife. His prescription was completely correct\u2014IDM 2.0, rebuilding manufacturing, catching up to TSMC\u2014but the patient refused to take the medicine."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Ryan's failure: Real power, wrong direction."})," Ryan's power at Sony was unchallenged\u2014he could close Japan Studio, replace Shuhei Yoshida, and order Naughty Dog to make online games. No interest group could stop him. But he pushed the entire company in a direction that Sony's DNA did not support. Sony's moat was single-player narrative games\u2014",(0,s.jsx)(t.em,{children:"The Last of Us"}),", ",(0,s.jsx)(t.em,{children:"God of War"}),", ",(0,s.jsx)(t.em,{children:"Uncharted"}),", ",(0,s.jsx)(t.em,{children:"Ghost of Tsushima"}),". The capabilities required for live-service games\u2014live operations, community management, continuous production of seasonal content\u2014were muscles Sony had never built. Ryan made a group of marathon runners enter a boxing match."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Nadella's gamble: Real power, undetermined direction."})," Nadella is the most powerful of the three\u2014he controls a company worth over three trillion dollars, and the board trusts him completely. His logic in shifting Xbox's resources to AI is, from a business perspective, unassailable. But the return cycle for AI investment is unknown. A $100 billion annual capital expenditure\u2014what if the commercialization of AI is three years slower than expected? What if OpenAI's technology is surpassed by Google or Anthropic? What if the AI bubble bursts?"]}),"\n",(0,s.jsx)(t.p,{children:"Gelsinger had the right prescription, but the system wouldn't let him take it. Ryan's system let him do anything, but the prescription he wrote was poison. Nadella's system lets him do anything, and his prescription might be right\u2014but the bill won't be known for another five years."}),"\n",(0,s.jsx)(t.p,{children:"Three modes of failure. Three mirrors. But they reflect the exact same image."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"v-the-same-root-cause-of-the-disease",children:"V. The Same Root Cause of the Disease"}),"\n",(0,s.jsx)(t.p,{children:"Microsoft dismantled Xbox. Sony dismantled studios. On the surface, the two companies were doing completely different things\u2014one chasing AI, the other chasing live-service games."}),"\n",(0,s.jsxs)(t.p,{children:["But if you step back and look closely at the logic of their decisions, you will find that what drives these two decisions is ",(0,s.jsx)(t.strong,{children:"the exact same spell cast by the capital markets"}),"."]}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Turn one-time transactions into recurring revenue."})}),"\n",(0,s.jsx)(t.p,{children:"Microsoft's version: Turn the sale of game consoles (a one-time hardware transaction) into selling Game Pass subscriptions (recurring monthly fees), and then into selling AI cloud services (recurring enterprise contracts). Every step makes the revenue structure look \"higher quality\" in the eyes of Wall Street. Nadella slashed nearly half the staff of Turn 10 Studios\u2014the development team behind the ForzaTech engine, one of Xbox's last remaining low-level technical vanguards\u2014and simultaneously used the saved money to buy NVIDIA GPUs to build AI data centers. Because AI's price-to-dream ratio is high, Wall Street loves to see it."}),"\n",(0,s.jsx)(t.p,{children:"Sony's version: Turn the sale of a $70 single-player game (a one-time purchase) into the microtransactions of a live-service game (recurring consumption). Ryan butchered single-player studios and forced all teams to pivot to live-service games. Because the P/E ratio for recurring revenue is higher than for one-time buyouts, Wall Street loves to see it."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Two paths, one destination: paying protection money to Wall Street."})}),"\n",(0,s.jsx)(t.p,{children:"This is not a metaphor. CEOs of publicly traded companies have a fiduciary duty to shareholders\u2014to maximize shareholder value. If Wall Street believes recurring revenue is worth a higher P/E ratio than one-time transactions, then all CEOs have an obligation to push their revenue structures in that direction. A CEO who doesn't push will be replaced\u2014Chapter 9's Gelsinger is a living example."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:'Nadella wasn\'t "wrong." Ryan wasn\'t "wrong." They both perfectly fulfilled their responsibilities to shareholders as CEOs of publicly traded companies.'})," But the cost was that they personally dismantled the invisible supply chain described in Chapters 7 and 8."]}),"\n",(0,s.jsxs)(t.p,{children:["And this is exactly what is most terrifying: ",(0,s.jsx)(t.strong,{children:'Under the logic of capital, destroying the cornerstones of technology is actually the "most rational and profitable" behavior.'})]}),"\n",(0,s.jsx)(t.p,{children:"This logic has a fatal blind spot."}),"\n",(0,s.jsx)(t.p,{children:"It assumes that gaming is merely a commodity\u2014a revenue stream that can be repackaged, repriced, and reallocated. It doesn't care what role gaming plays in the broader technological ecosystem."}),"\n",(0,s.jsx)(t.p,{children:"This book has spent nine chapters explaining that role."}),"\n",(0,s.jsx)(t.p,{children:"Chapter 7: Gamers' money fed CUDA. Inside every GeForce sold were general-purpose compute cores gamers didn't use, amortizing ten years of R&D costs for the AI revolution."}),"\n",(0,s.jsx)(t.p,{children:"Chapter 8: Gaming GPUs are the stress test arena for TSMC's advanced processes. The 608-square-millimeter die of the RTX 4090\u2014five and a half times larger than an iPhone chip\u2014forced TSMC to push the yield of its 5nm process to the absolute limit. Without this stress test, the H100 could never have been mass-produced."}),"\n",(0,s.jsx)(t.p,{children:"Chapter 8 also stated another fact: Console SoCs are TSMC's invisible ballast. Orders for the PS5 and Xbox Series X\u2014lasting seven to ten years and shipping tens of millions of units\u2014filled the capacity voids during the iPhone's off-season, keeping fab utilization at high levels. This was one of the prerequisites for TSMC daring to pour astronomical capital into building next-generation nodes."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Gaming is not a commodity. Gaming is a stress test arena plus an R&D funding pool."})," The cost of tearing it down won't appear on this year's financial reports. The cost will only materialize five or ten years from now."]}),"\n",(0,s.jsx)(t.p,{children:"And Microsoft and Sony are tearing it down simultaneously. Both CEOs are paying protection money to Wall Street. The names of the premiums are different\u2014one is called AI, the other live-service games\u2014but the bricks being torn down come from the exact same wall."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"vi-closing-arguments",children:"VI. Closing Arguments"}),"\n",(0,s.jsx)(t.p,{children:"That pattern appears for the last time. The eighth time. And the most dangerous time."}),"\n",(0,s.jsx)(t.p,{children:"Because the previous seven variations locked in other people\u2014consumers, developers, AI researchers, OEMs. And the ones tearing down the walls were also other people\u2014Valve, AMD, the open-source community."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"This time, the ones tearing down the wall are the owners themselves."})}),"\n",(0,s.jsx)(t.p,{children:"Microsoft is dismantling Xbox. Sony is dismantling studios. Both companies are using the same reason: We need to put our resources into more valuable places. Microsoft says that place is AI. Sony says that place is live-service games."}),"\n",(0,s.jsxs)(t.p,{children:["But the things they are tearing down\u2014long-term chip orders for tens of millions of consoles annually, a consumer hardware market pushing the extreme limits of GPU performance, the demand for stress tests that forces TSMC to push yields to the extreme\u2014these things are not on their balance sheets. ",(0,s.jsx)(t.strong,{children:"What they are tearing down is an invisible supply chain stretching from the gamer's pocket to the silicon of AI chips."})]}),"\n",(0,s.jsx)(t.p,{children:"The logic of Chapter 8 works like this: Gamers spend $1,599 to buy an RTX 4090 \u2192 NVIDIA uses this money to place large-die orders with TSMC \u2192 TSMC uses these orders to hone large-die yields \u2192 Once yields mature, they are used to build the H100 \u2192 The H100 drives global AI training."}),"\n",(0,s.jsx)(t.p,{children:"The starting point of this chain is gaming. If the console market shrinks\u2014if Xbox becomes a brand label instead of a piece of hardware\u2014that chain loses a link. Long-term orders for console SoCs shrink, and TSMC's capacity balancer loosens. If the consumer GPU market is eroded by cloud streaming, NVIDIA's gaming revenue drops, and the base for amortizing the R&D tax shrinks\u2014the cost of every AI card will rise."}),"\n",(0,s.jsx)(t.p,{children:"No one has ever asked this question in the boardrooms of Microsoft or Sony. Because this chain is too long. Between the layoffs at Xbox and the capacity planning at TSMC, there are too many layers. And Wall Street only looks at the next quarter."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Convenience attracts Wall Street (higher P/E ratios) \u2192 Wall Street's pressure locks in the CEO's decision space \u2192 The CEO tears down gaming assets to feed AI or live-service games \u2192 Gaming's function as a stress test arena and R&D funding pool is weakened \u2192 The cost of this weakening only materializes five to ten years later \u2192 But by then, the things torn down can never be brought back."})}),"\n",(0,s.jsx)(t.p,{children:"In the previous seven variations, the cost of the pattern was reversible\u2014at least theoretically. Microsoft could re-invest in DirectX. NVIDIA could open-source CUDA (though it won't). TSMC could take on new clients."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"This time is irreversible."})," You can build a fab in three years, but you cannot rebuild the creative culture of a disbanded game studio in three years. You can spend money to hire back engineers, but you cannot buy back the unspoken chemistry between a team that has honed the same IP for a decade. Japan Studio is closed, and it stays closed. Tango Gameworks was picked up by Krafton. Arkane Austin is scattered. Bluepoint is scattered. The capabilities of these teams\u2014to make games like ",(0,s.jsx)(t.em,{children:"Prey"}),", ",(0,s.jsx)(t.em,{children:"Hi-Fi Rush"}),", ",(0,s.jsx)(t.em,{children:"Demon's Souls"}),", and ",(0,s.jsx)(t.em,{children:"Bloodborne"})," that are revered by hardcore players as masterpieces, that drive hardware sales, and that force GPUs and CPUs to push their performance to the absolute limit\u2014cannot be bought back with money."]}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Gaming is the stress test arena for technological evolution. And that stress test arena is being personally torn down by its owners. Not because of foreign invaders, but because the owners feel the land is worth more if used to build something else."})}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.h2,{id:"vii-the-loot-is-still-being-divided",children:"VII. The Loot is Still Being Divided"}),"\n",(0,s.jsx)(t.p,{children:"Back to February 23, 2026. Phil Spencer retires. Asha Sharma takes over."}),"\n",(0,s.jsx)(t.p,{children:'A gaming journalist wrote a sentence in an article: "The soul of Xbox has left the building."'}),"\n",(0,s.jsx)(t.p,{children:"But the soul never lived in that building to begin with."}),"\n",(0,s.jsx)(t.p,{children:"Chapter 3 already stated it: Xbox was never built for the players from day one. It was built to block Sony's threat to Windows. A wall, not a city. The people living behind the wall\u2014the players who bought the Xbox, subscribed to Game Pass, and trusted the exclusivity promises\u2014their investment was never on Microsoft's balance sheet."}),"\n",(0,s.jsx)(t.p,{children:"Did Spencer know this? Probably. But he stayed for thirty-eight years, held on until the very last moment, and then handed the keys over to an AI executive."}),"\n",(0,s.jsx)(t.p,{children:"Sony's situation is more complex. Because PlayStation truly was a city\u2014a city with residents, culture, and a sense of belonging. The developers of Japan Studio, the writers of Naughty Dog, the craftsmen of Bluepoint\u2014they weren't chips; they were residents. Jim Ryan used Wall Street's logic to tear down several walls of this city, and then retired. The people left behind are picking up the pieces."}),"\n",(0,s.jsx)(t.p,{children:"But picking up the pieces does not equal rebuilding."}),"\n",(0,s.jsxs)(t.p,{children:["Because what was torn down weren't just studios. What was torn down was a signal\u2014",(0,s.jsx)(t.strong,{children:"a signal telling game developers worldwide: in the eyes of major platform holders, your work is merely a revenue genre. If your revenue genre isn't the kind Wall Street prefers, you are a replaceable part."})]}),"\n",(0,s.jsx)(t.p,{children:"The long-term effect of this signal runs deeper than any layoff. Because it changes the flow of talent. The best game developers will ask themselves: Do I want to bet my career on a company that might shut down my studio at any moment simply because of Wall Street's preferences?"}),"\n",(0,s.jsx)(t.p,{children:'The answer is increasingly "No." And where do these people go? Some go to indie development. Some go to AI. Some leave the industry altogether.'}),"\n",(0,s.jsx)(t.p,{children:"What they take with them\u2014their understanding of hardware limits, their intuition for real-time rendering, their obsession that anything below sixty frames per second is unacceptable\u2014happens to be the starting point of the invisible supply chain described in Chapters 7 and 8."}),"\n",(0,s.jsx)(t.p,{children:"No one cares. Because the bill won't arrive for another ten years."}),"\n",(0,s.jsx)(t.p,{children:"This is the final chain of causality in this book. And the only one still unfolding."}),"\n",(0,s.jsxs)(t.p,{children:["Microsoft spent $69 billion to buy Activision Blizzard, then sent its games to its competitor's console. Sony spent over $200 million making a game that lived for fourteen days. Both companies, in different ways, did the exact same thing: ",(0,s.jsx)(t.strong,{children:"treating gaming as a means rather than an end, and treating players as bargaining chips rather than customers."})]}),"\n",(0,s.jsx)(t.p,{children:"This sentence was written at the end of Chapter 3. Back then, it was a preview. Now, it is a settlement."}),"\n",(0,s.jsx)(t.p,{children:"And on the settlement bill, the line with the largest amount is not the $69 billion, not the $200 million, not the $100 billion AI capital expenditure."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:'The line with the largest amount is a number no one can yet calculate: When the world\'s two largest gaming platform holders simultaneously decide "gaming is not our core business," how big of a hole will the stress test arenas, R&D funding pools, and long-term chip orders they simultaneously tear down leave in the semiconductor supply chains and AI infrastructure of the next decade?'})}),"\n",(0,s.jsx)(t.p,{children:"No one is asking this question."}),"\n",(0,s.jsx)(t.p,{children:"But TSMC's engineers in Hsinchu might already be feeling it."}),"\n",(0,s.jsx)(t.hr,{}),"\n",(0,s.jsx)(t.p,{children:"That is the story of the finale."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.img,{src:n(6610).A+"",width:"2816",height:"1536"})})]})}function c(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},6610(e,t,n){n.d(t,{A:()=>s});const s=n.p+"assets/images/ch10_en-1434af6873fef49562a4140137569cb4.png"},8453(e,t,n){n.d(t,{R:()=>r,x:()=>o});var s=n(6540);const i={},a=s.createContext(i);function r(e){const t=s.useContext(a);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:r(e.components),s.createElement(a.Provider,{value:t},e.children)}}}]);